/* Drive Results Slider — static S3 replacement v3 */
(function() {
  var initialized = false;

  function init() {
    if (initialized) return;
    initialized = true;

    var W = document.querySelector('.drive_slider');
    if (!W) return;

    /* Override CSS issues from module that expects owl-carousel */
    W.style.setProperty('overflow', 'visible', 'important');
    W.style.setProperty('transition', 'none', 'important');
    W.style.setProperty('width', '100%', 'important');
    W.style.setProperty('display', 'block', 'important');
    W.style.removeProperty('height');

    var slides = W.querySelectorAll('.dss-slide');
    var total  = slides.length;
    var cur    = 0;
    if (!total) return;

    /* CRITICAL: dss-slide must have explicit width:100% so children render properly */
    slides.forEach(function(s) {
      s.style.setProperty('width', '100%', 'important');
      s.style.setProperty('box-sizing', 'border-box', 'important');
    });

    var svgP = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 36"><path fill="rgba(0,239,210,1)" d="M14.27,35.5a1.53,1.53,0,0,1-1.18-.57L.55,18.92a1.49,1.49,0,0,1,0-1.85l12.54-16a1.5,1.5,0,0,1,2.36,1.86L3.63,18,15.45,33.07a1.5,1.5,0,0,1-.25,2.11A1.46,1.46,0,0,1,14.27,35.5Z"/></svg>';
    var svgN = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 36" style="transform:rotate(180deg)"><path fill="rgba(0,239,210,1)" d="M14.27,35.5a1.53,1.53,0,0,1-1.18-.57L.55,18.92a1.49,1.49,0,0,1,0-1.85l12.54-16a1.5,1.5,0,0,1,2.36,1.86L3.63,18,15.45,33.07a1.5,1.5,0,0,1-.25,2.11A1.46,1.46,0,0,1,14.27,35.5Z"/></svg>';

    /* Build arrow bar once */
    var arrowBar = document.getElementById('dss-arrow-bar');
    if (!arrowBar) {
      arrowBar = document.createElement('div');
      arrowBar.className = 'drive_slider_arrows';
      arrowBar.id = 'dss-arrow-bar';
      arrowBar.innerHTML =
        '<div class="drive_slider_arrows_container">' +
          '<div class="drive_slider_nav driver_slider_prev disabled" id="dss-prev">' + svgP + '</div>' +
          '<div class="drive_slider_nav driver_slider_next" id="dss-next">' + svgN + '</div>' +
        '</div>';
      W.parentNode.insertBefore(arrowBar, W.nextSibling);
    }

    var prevBtn  = document.getElementById('dss-prev');
    var nextBtn  = document.getElementById('dss-next');
    var bgColors  = ['#353544', '#353544', '#e5e5f0'];
    var txtColors = ['#ffffff', '#ffffff', '#353544'];

    function updateUI() {
      arrowBar.style.backgroundColor = bgColors[cur];
      var sec = document.querySelector('.dnd_area-row-4-background-layers');
      if (sec) {
        sec.style.setProperty('background-image', 'none', 'important');
        sec.style.setProperty('background-color', bgColors[cur], 'important');
      }
      var ttl = document.querySelector('.helper_change_color1');
      if (ttl) ttl.style.setProperty('color', txtColors[cur], 'important');
      prevBtn.classList.toggle('disabled', cur === 0);
      nextBtn.classList.toggle('disabled', cur === total - 1);
    }

    function go(n) {
      if (n < 0 || n >= total) return;
      slides[cur].style.setProperty('display', 'none', 'important');
      slides[cur].classList.remove('dss-active');
      cur = n;
      slides[cur].style.setProperty('display', 'block', 'important');
      slides[cur].classList.add('dss-active');
      updateUI();
    }

    /* Force initial display state */
    slides.forEach(function(s, idx) {
      if (idx === 0) {
        s.style.setProperty('display', 'block', 'important');
        s.classList.add('dss-active');
      } else {
        s.style.setProperty('display', 'none', 'important');
        s.classList.remove('dss-active');
      }
    });

    updateUI();

    prevBtn.addEventListener('click', function() { go(cur - 1); });
    nextBtn.addEventListener('click', function() { go(cur + 1); });
  }

  if (document.readyState === 'complete') {
    init();
  } else {
    window.addEventListener('load', init);
  }
})();
